// ── Logo ──────────────────────────────────────────────────────────────────────
function FioLogo({ color = "#fff", size = 22 }) {
  const isWhite = color === "#fff" || color === "white";
  return (
    <div style={{ display: "flex", alignItems: "center" }}>
      <img src="/logo-v2.png" alt="Fio Raiz" style={{ height: size * 2.8, width: "auto", display: "block", filter: isWhite ? "brightness(0) invert(1)" : "none" }} />
    </div>
  );
}

// ── Image component com fallback ──────────────────────────────────────────────
function Img({ src, alt, style, gradient }) {
  const [err, setErr] = useState(false);
  if (err || !src) {
    return (
      <div style={{ ...style, background: gradient || "linear-gradient(135deg, #e8e8e4 0%, #d0d0cc 100%)", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <span style={{ fontSize: 11, color: "#aaa", letterSpacing: "0.08em", textTransform: "uppercase" }}>imagem</span>
      </div>
    );
  }
  return <img src={src} alt={alt} style={{ ...style, objectFit: "cover" }} onError={() => setErr(true)} />;
}

